from collections import defaultdict, deque

def longest_special_path(nums, edges):
    n = len(nums)
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def dfs(node, parent):
        max_len = 0
        min_nodes = float('inf')
        path_values = defaultdict(int)
        path_values[nums[node]] += 1
        if path_values[nums[node]] > 2:
            return 0, float('inf')
        queue = deque([(node, 1)])
        while queue:
            node, depth = queue.popleft()
            max_len = max(max_len, depth)
            if depth > 0 and path_values[nums[node]] == 2:
                min_nodes = min(min_nodes, depth)
            for neighbor in graph[node]:
                if neighbor != parent:
                    path_values[nums[neighbor]] += 1
                    if path_values[nums[neighbor]] > 2:
                        path_values[nums[neighbor]] = 0
                        break
                    queue.append((neighbor, depth + 1))
            else:
                continue
            break
        return max_len, min_nodes if min_nodes != float('inf') else 0

    max_len = 0
    min_nodes = float('inf')
    for i in range(n):
        length, nodes = dfs(i, -1)
        if length > max_len:
            max_len = length
            min_nodes = nodes
        elif length == max_len and nodes < min_nodes:
            min_nodes = nodes
    if max_len == 0:
        return [0, 0]
    return [max_len, min_nodes]

