                dfs(child, node, path)
        path.pop()

    def is_special_path(nums, path):
        count = defaultdict(int)
        for node in path:
            count[nums[node]] += 1
            if count[nums[node]] > 2:
                return False
        return True

    for i in range(len(nums)):
