def dfs_util(node, target, path, visited, graph, nums):
    if node == target:
        path.append(node)
        return True
    visited.add(node)
    path.append(node)
    for child in graph[node]:
        if child not in visited:
            if dfs_util(child, target, path, visited, graph, nums):
                return True
    path.pop()
    return False

