def journeyToMoon(n, astronaut):
    pairs = set()
    for i in range(len(astronaut)):
        pairs.add((astronaut[i][0], astronaut[i][1]))
    d = {}
    for i in range(n):
        d[i] = i
    def find(a):
        acopy = a
        while a != d[a]:
            a = d[a]
        while acopy != a:
            d[acopy] = a
            acopy = d[acopy]
        return a
    def union(a, b):
        d[find(b)] = find(a)
    for pair in pairs:
        union(pair[0], pair[1])
    c = {}
    for i in range(n):
        fi = find(i)
        if fi not in c:
            c[fi] = 0
        c[fi] += 1
    ans = 0
    for country in c.values():
        ans += (country * (country - 1)) // 2
    return ans

